import{_ as i,o as l,c as a,ag as r}from"./chunks/framework.CvgP6Fyv.js";const v=JSON.parse('{"title":"Gestion de la TVA","description":"","frontmatter":{},"headers":[],"relativePath":"fr/features/vat.md","filePath":"fr/features/vat.md"}'),o={name:"fr/features/vat.md"};function t(s,e,u,n,d,c){return l(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="gestion-de-la-tva" tabindex="-1">Gestion de la TVA <a class="header-anchor" href="#gestion-de-la-tva" aria-label="Permalink to &quot;Gestion de la TVA&quot;">​</a></h1><p>Suivez, calculez et gerez vos obligations de taxe sur la valeur ajoutee (TVA) avec le verrouillage des periodes et le suivi des echeances.</p><h2 id="vue-d-ensemble" tabindex="-1">Vue d&#39;ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d&#39;ensemble&quot;">​</a></h2><p>La page TVA vous offre une vision claire de votre situation fiscale :</p><ul><li><strong>TVA collectee</strong> -- Taxe facturee sur vos factures</li><li><strong>TVA deductible</strong> -- Taxe payee sur vos depenses professionnelles</li><li><strong>TVA nette</strong> -- Le montant que vous devez (ou pouvez recuperer)</li></ul><h2 id="periodes-de-tva" tabindex="-1">Periodes de TVA <a class="header-anchor" href="#periodes-de-tva" aria-label="Permalink to &quot;Periodes de TVA&quot;">​</a></h2><p>La TVA est organisee par periode (mensuelle ou trimestrielle, selon votre juridiction) :</p><ul><li>Consultez les calculs de TVA par periode</li><li>Voyez les ventilations detaillees par taux de TVA</li><li>Suivez quelles periodes ont ete declarees</li></ul><h2 id="verrouillage-des-periodes" tabindex="-1">Verrouillage des periodes <a class="header-anchor" href="#verrouillage-des-periodes" aria-label="Permalink to &quot;Verrouillage des periodes&quot;">​</a></h2><p>Apres avoir depose votre declaration de TVA, verrouillez la periode pour eviter les modifications accidentelles :</p><ol><li>Allez sur la page TVA</li><li>Selectionnez la periode que vous avez declaree</li><li>Cliquez sur <strong>Verrouiller la periode</strong></li></ol><h3 id="ce-que-le-verrouillage-fait" tabindex="-1">Ce que le verrouillage fait <a class="header-anchor" href="#ce-que-le-verrouillage-fait" aria-label="Permalink to &quot;Ce que le verrouillage fait&quot;">​</a></h3><ul><li>Empeche la modification ou la suppression des factures et depenses de la periode verrouillee</li><li>Affiche une banniere d&#39;avertissement sur les documents des periodes verrouilees</li><li>Garantit que vos chiffres declares restent coherents avec vos archives</li></ul><h3 id="deverrouillage" tabindex="-1">Deverrouillage <a class="header-anchor" href="#deverrouillage" aria-label="Permalink to &quot;Deverrouillage&quot;">​</a></h3><p>Si vous devez apporter des corrections apres le verrouillage :</p><ol><li>Allez sur la page TVA</li><li>Trouvez la periode verrouillee</li><li>Cliquez sur <strong>Deverrouiller</strong></li><li>Effectuez vos corrections</li><li>Reverrouillez une fois termine</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Ne deverrouillez les periodes que lorsque vous devez deposer une correction. Un deverrouillage frequent annule l&#39;objectif de cette mesure de conformite.</p></div><h2 id="suivi-des-echeances" tabindex="-1">Suivi des echeances <a class="header-anchor" href="#suivi-des-echeances" aria-label="Permalink to &quot;Suivi des echeances&quot;">​</a></h2><p>MyCompanyDesk suit les echeances de declaration de TVA selon votre pays :</p><ul><li>Indicateurs visuels pour les echeances a venir</li><li>Avertissements lorsqu&#39;une echeance approche</li><li>Statut clair indiquant quelles periodes necessitent votre attention</li></ul><h2 id="indicateur-de-pays" tabindex="-1">Indicateur de pays <a class="header-anchor" href="#indicateur-de-pays" aria-label="Permalink to &quot;Indicateur de pays&quot;">​</a></h2><p>Vos parametres de TVA respectent le pays d&#39;immatriculation de votre entreprise. Cela affecte :</p><ul><li>Les taux de TVA normal et reduit</li><li>La structure des periodes de declaration (mensuelle/trimestrielle)</li><li>Les calculs d&#39;echeances</li><li>L&#39;applicabilite de l&#39;autoliquidation</li></ul><h2 id="autoliquidation" tabindex="-1">Autoliquidation <a class="header-anchor" href="#autoliquidation" aria-label="Permalink to &quot;Autoliquidation&quot;">​</a></h2><p>Pour les transactions intracommunautaires entre entreprises, activez l&#39;autoliquidation :</p><ol><li>Assurez-vous que le client dispose d&#39;un numero de TVA intracommunautaire valide</li><li>Activez l&#39;<strong>autoliquidation</strong> dans Entreprise &gt; Fonctionnalites</li><li>Lors de la creation d&#39;une facture pour un client B2B de l&#39;UE, selectionnez l&#39;option d&#39;autoliquidation</li><li>La facture affichera 0 % de TVA avec la mention d&#39;autoliquidation</li></ol><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Verrouillez les periodes immediatement apres la declaration pour eviter les modifications accidentelles</li><li>Consultez le rapport de TVA dans les <a href="/fr/features/reports">Rapports</a> pour une vue plus large</li><li>Assurez-vous que votre numero de TVA et ceux de vos clients sont correctement renseignes</li><li>Utilisez le profil de tableau de bord comptable/expert-comptable pour une vue axee sur la TVA</li></ul>',28)])])}const h=i(o,[["render",t]]);export{v as __pageData,h as default};
